xpath.script:
//
(function () {
    "use strict";

    // ---- error keyword detection (for GPS warning) ----
    var ERROR_KEYWORDS = [
        "pilih untuk menghitung",
        "error",
        "gagal",
        "tidak tersedia",
        "tidak dapat",
        "no rate",
        "unavailable"
    ];
    var PRICE_PATTERN = /Rp\s?\d|\d{3,}\s?(?:rb|ribu|jt|juta)?/i;

    // ---- modal state machine ----
    // not_shown -> showing -> confirmed | dismissed
    var modalState = "not_shown";
    var mapInstance = null;
    var mapLibreLoading = false;
    var mapLibreQueue = [];

    function getSelectedRadio() {
        return document.querySelector(
            'input[name="delivery_type"]:checked'
        );
    }

    function getSelectedPriceBadge(radio) {
        if (!radio) return null;
        var li = radio.closest('li.o_delivery_carrier_select');
        if (!li) return null;
        return li.querySelector('.o_wsale_delivery_badge_price');
    }

    function isPickupSelected(radio) {
        return radio && radio.dataset &&
               radio.dataset.isPickup === '1';
    }

    function isDistanceCarrier(radio) {
        return radio &&
               radio.getAttribute('delivery_type') === 'osrm_distance';
    }

    function priceBadgeHasError(badge) {
        if (!badge) return true;
        var text = (badge.textContent || '').trim().toLowerCase();
        if (!text) return true;
        if (PRICE_PATTERN.test(text)) return false;
        for (var i = 0; i < ERROR_KEYWORDS.length; i++) {
            if (text.indexOf(ERROR_KEYWORDS[i]) !== -1) return true;
        }
        return false;
    }

    // ---- modal helpers ----
    function getModalEl() {
        return document.getElementById('wl_delivery_confirm_modal');
    }

    // Bootstrap 5 is loaded in Odoo 17 but the global
    // `bootstrap` namespace is NOT exposed on window.
    // Only individual classes (Modal, Popover, etc.)
    // and the jQuery .modal() plugin are available.
    // This wrapper picks whichever is available.
    function getModalInstance(el) {
        if (typeof window.bootstrap !== 'undefined' &&
            window.bootstrap.Modal) {
            return window.bootstrap.Modal.getOrCreateInstance(el);
        }
        if (typeof window.Modal !== 'undefined' &&
            window.Modal.getOrCreateInstance) {
            return window.Modal.getOrCreateInstance(el);
        }
        // jQuery fallback
        if (typeof window.jQuery !== 'undefined') {
            var $el = window.jQuery(el);
            return {
                show: function () { $el.modal('show'); },
                hide: function () { $el.modal('hide'); }
            };
        }
        return null;
    }

    function getPartnerCoords() {
        var modal = getModalEl();
        if (!modal) return {lat: 0, lng: 0, hasCoords: false};
        var lat = parseFloat(modal.dataset.lat) || 0;
        var lng = parseFloat(modal.dataset.lng) || 0;
        // 0,0 means unset (Indonesia is never at lat=0 lng=0)
        var has = (lat !== 0 || lng !== 0);
        return {lat: lat, lng: lng, hasCoords: has};
    }

    function loadMapLibre(callback) {
        if (window.maplibregl) {
            callback();
            return;
        }
        mapLibreQueue.push(callback);
        if (mapLibreLoading) return;
        mapLibreLoading = true;

        // CSS
        var link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.css';
        document.head.appendChild(link);

        // JS
        var script = document.createElement('script');
        script.src = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.js';
        script.async = true;
        script.onload = function () {
            var q = mapLibreQueue;
            mapLibreQueue = [];
            for (var i = 0; i < q.length; i++) {
                try { q[i](); } catch (e) { console.warn(e); }
            }
        };
        document.head.appendChild(script);
    }

    function applyCustomMapStyle(map) {
        if (!map || !map.getStyle) return;
        var layers = map.getStyle().layers || [];
        for (var i = 0; i < layers.length; i++) {
            var layer = layers[i];
            var sl = layer['source-layer'] || '';
            var lid = layer.id || '';

            // Roads: maroon for inner, dark maroon for casing
            if (layer.type === 'line' && sl === 'transportation') {
                var color = '#7a0c14';
                if (lid.indexOf('casing') !== -1) {
                    color = '#5a080e';
                } else if (lid.indexOf('minor') !== -1 ||
                           lid.indexOf('path') !== -1 ||
                           lid.indexOf('pier') !== -1) {
                    color = '#a02030';
                }
                try {
                    map.setPaintProperty(lid, 'line-color', color);
                } catch (e) {}
            }

            // Water: light blue
            if ((layer.type === 'fill' && sl === 'water') ||
                (layer.type === 'line' && sl === 'waterway')) {
                try {
                    if (layer.type === 'fill') {
                        map.setPaintProperty(lid, 'fill-color', '#cfe4f5');
                    } else {
                        map.setPaintProperty(lid, 'line-color', '#a8d0ed');
                    }
                } catch (e) {}
            }

            // Buildings: warm cream fill
            if (layer.type === 'fill' && sl === 'building') {
                try {
                    map.setPaintProperty(lid, 'fill-color', '#fff7e0');
                    map.setPaintProperty(lid, 'fill-opacity', 0.9);
                } catch (e) {}
            }

            // Parks / landuse: light green
            if (layer.type === 'fill' && sl === 'landuse') {
                try {
                    map.setPaintProperty(lid, 'fill-color', '#e8f5e8');
                } catch (e) {}
            }

            // Aeroway (runways): maroon, lighter
            if (layer.type === 'line' && sl === 'aeroway') {
                try {
                    map.setPaintProperty(lid, 'line-color', '#b03040');
                } catch (e) {}
            }

            // NEW v3.10.13: Admin boundary lines.
            // Recolor country/province boundaries to subtle
            // maroon. Desa (village) boundaries get a stronger
            // maroon dashed style via a custom layer in
            // addCustomLayers() below.
            if (layer.type === 'line' && sl === 'boundary') {
                try {
                    map.setPaintProperty(lid, 'line-color', '#7a0c14');
                    map.setPaintProperty(lid, 'line-opacity', 0.4);
                } catch (e) {}
            }

            // NEW v3.10.13: POI labels. Recolor text to
            // dark maroon with white halo so it pops on the
            // maroon roads. Bump text-size up a notch.
            if (layer.type === 'symbol' && sl === 'poi') {
                try {
                    map.setPaintProperty(lid, 'text-color', '#5a080e');
                    map.setPaintProperty(lid, 'text-halo-color', '#ffffff');
                    map.setPaintProperty(lid, 'text-halo-width', 2);
                } catch (e) {}
                try {
                    map.setLayoutProperty(lid, 'text-size', 12);
                } catch (e) {}
            }

            // NEW v3.10.13: Building name labels. Make
            // them maroon with cream halo.
            if (layer.type === 'symbol' && sl === 'building') {
                try {
                    map.setPaintProperty(lid, 'text-color', '#7a0c14');
                    map.setPaintProperty(lid, 'text-halo-color', '#fff7e0');
                    map.setPaintProperty(lid, 'text-halo-width', 1.8);
                } catch (e) {}
                try {
                    map.setLayoutProperty(lid, 'text-size', 11);
                } catch (e) {}
            }

            // NEW v3.10.13: Place labels (city/town/village).
            // Dark maroon text with white halo for readability.
            if (layer.type === 'symbol' && sl === 'place') {
                try {
                    map.setPaintProperty(lid, 'text-color', '#3a0508');
                    map.setPaintProperty(lid, 'text-halo-color', '#ffffff');
                    map.setPaintProperty(lid, 'text-halo-width', 2.5);
                } catch (e) {}
            }

            // NEW v3.10.13: Road labels (street names).
            // White text with dark halo so they are readable
            // on the maroon road background.
            if (layer.type === 'symbol' &&
                (sl === 'transportation_name' || lid.indexOf('road-label') !== -1)) {
                try {
                    map.setPaintProperty(lid, 'text-color', '#ffffff');
                    map.setPaintProperty(lid, 'text-halo-color', '#5a080e');
                    map.setPaintProperty(lid, 'text-halo-width', 1.8);
                } catch (e) {}
            }
        }
    }

    // ---- NEW v3.10.13: custom layers for desa boundaries,
    //      house numbers, and Indonesian landmark highlights.
    //      These are added AFTER the style loads and are
    //      idempotent (safe to call multiple times thanks to
    //      the getLayer guard). ----
    function addCustomLayers(map) {
        if (!map) {
            console.log('WL: addCustomLayers skip - no map');
            return;
        }
        if (!map.isStyleLoaded) {
            console.log('WL: addCustomLayers skip - no isStyleLoaded method');
            return;
        }
        // Do not attempt until the style is fully loaded.
        try {
            if (!map.isStyleLoaded()) {
                console.log('WL: addCustomLayers skip - style not yet loaded');
                return;
            }
        } catch (e) {
            console.log('WL: addCustomLayers skip - isStyleLoaded threw: ' + e.message);
            return;
        }

        // Detect the source name (liberty uses 'openmaptiles'
        // but be defensive in case it changes).
        var srcName = 'openmaptiles';
        try {
            var srcs = map.getStyle().sources || {};
            if (srcs['openmaptiles']) {
                srcName = 'openmaptiles';
            } else {
                // pick the first source
                var keys = Object.keys(srcs);
                if (keys.length) {
                    srcName = keys[0];
                    console.log('WL: openmaptiles source not found, using: ' + srcName);
                }
            }
        } catch (e) {}

        console.log('WL: addCustomLayers running, source=' + srcName);

        // Helper to add a layer with individual error logging
        function addOne(layerConfig, beforeId) {
            try {
                if (map.getLayer(layerConfig.id)) {
                    return;  // already added
                }
                // Set the source name dynamically
                layerConfig.source = srcName;
                if (beforeId) {
                    map.addLayer(layerConfig, beforeId);
                } else {
                    map.addLayer(layerConfig);
                }
                console.log('WL: added layer ' + layerConfig.id);
            } catch (e) {
                console.warn('WL: failed to add layer ' + layerConfig.id + ': ' + e.message);
            }
        }

        // 1. Desa (village) administrative boundary.
        addOne({
            id: 'wl-desa-boundary',
            type: 'line',
            'source-layer': 'boundary',
            filter: ['match', ['get', 'admin_level'],
                ['7', '8'], true, false],
            paint: {
                'line-color': '#7a0c14',
                'line-width': {
                    stops: [
                        [10, 0.8],
                        [14, 1.5],
                        [17, 2.5]
                    ]
                },
                'line-dasharray': [3, 2],
                'line-opacity': 0.75
            }
        });

        // 2. House number labels (visible at zoom 17+).
        addOne({
            id: 'wl-housenumber',
            type: 'symbol',
            'source-layer': 'housenumber',
            minzoom: 17,
            layout: {
                'text-field': '{housenumber}',
                'text-size': 10,
                'text-font': ['Noto Sans Regular'],
                'text-offset': [0, 0],
                'text-anchor': 'center',
                'text-allow-overlap': false
            },
            paint: {
                'text-color': '#5a080e',
                'text-halo-color': '#ffffff',
                'text-halo-width': 1.6
            }
        });

        // 3. Landmark highlight.
        addOne({
            id: 'wl-landmark-highlight',
            type: 'symbol',
            'source-layer': 'poi',
            minzoom: 12,
            filter: ['match', ['get', 'subclass'],
                [
                    'convenience',
                    'supermarket',
                    'place_of_worship',
                    'muslim',
                    'school',
                    'kindergarten',
                    'college',
                    'fuel'
                ],
                true, false],
            layout: {
                'text-field': ['coalesce',
                    ['get', 'name'],
                    ['get', 'name:latin'],
                    ['get', 'name_en'],
                    ''
                ],
                'text-size': 13,
                'text-font': ['Noto Sans Bold'],
                'text-offset': [0, 1.2],
                'text-anchor': 'top',
                'text-allow-overlap': false,
                'text-ignore-placement': false
            },
            paint: {
                'text-color': '#7a0c14',
                'text-halo-color': '#fff7e0',
                'text-halo-width': 2.8,
                'text-opacity': {
                    stops: [
                        [12, 0.0],
                        [13, 0.6],
                        [14, 1.0]
                    ]
                }
            }
        });

        // 4. Landmark icon background.
        addOne({
            id: 'wl-landmark-dot',
            type: 'circle',
            'source-layer': 'poi',
            minzoom: 12,
            filter: ['match', ['get', 'subclass'],
                [
                    'convenience',
                    'supermarket',
                    'place_of_worship',
                    'muslim',
                    'school',
                    'kindergarten',
                    'college',
                    'fuel'
                ],
                true, false],
            paint: {
                'circle-radius': {
                    stops: [
                        [12, 3],
                        [15, 5],
                        [17, 7]
                    ]
                },
                'circle-color': '#f5c400',
                'circle-stroke-color': '#7a0c14',
                'circle-stroke-width': 1.5,
                'circle-opacity': 0.9
            }
        }, 'wl-landmark-highlight');
    }

    // ---- NEW v3.10.14: load enrichment GeoJSON layers from
    //      the wl_osm_enrichment Odoo module. Renders real
    //      POIs (Indomaret, masjid, sekolah, SPBU, ...) and
    //      building centroids from the local Odoo database
    //      on top of the openfreemap base tiles. ----
    function loadEnrichmentLayers(map, lat, lng) {
        if (!map || !window.maplibregl) return;
        if (map._wlEnrichmentLoaded) return;  // idempotent
        map._wlEnrichmentLoaded = true;

        // Color palette per landmark_category
        var COLOR_BY_CATEGORY = {
            'minimarket': '#1976d2',   // blue (Indomaret/Alfamart)
            'masjid':     '#2e7d32',   // green (place_of_worship)
            'sekolah':    '#f57c00',   // orange (school)
            'spbu':       '#c62828',   // red (fuel)
            'pasar':      '#6a1b9a',   // purple (market)
            'kesehatan':  '#00838f',   // teal (pharmacy/clinic)
            'lainnya':    '#546e7a'    // grey (other)
        };
        function colorFor(cat) {
            return COLOR_BY_CATEGORY[cat] || '#546e7a';
        }

        // 1. Fetch + render buildings (small grey dots)
        function loadBuildings() {
            var url = '/api/osm/geojson/buildings' +
                '?lat=' + encodeURIComponent(lat) +
                '&lon=' + encodeURIComponent(lng) +
                '&radius=3000&limit=500';
            fetch(url, {credentials: 'same-origin'})
                .then(function (r) { return r.json(); })
                .then(function (geojson) {
                    if (!geojson || !geojson.features || !geojson.features.length) {
                        console.log('WL: enrichment buildings empty (rural area)');
                        return;
                    }
                    if (map.getSource('wl-enriched-buildings')) return;
                    map.addSource('wl-enriched-buildings', {
                        type: 'geojson',
                        data: geojson
                    });
                    map.addLayer({
                        id: 'wl-enriched-buildings-circle',
                        type: 'circle',
                        source: 'wl-enriched-buildings',
                        minzoom: 14,
                        paint: {
                            'circle-radius': {
                                stops: [[14, 1.5], [16, 2.5], [18, 4], [20, 6]]
                            },
                            'circle-color': '#9e9e9e',
                            'circle-stroke-color': '#616161',
                            'circle-stroke-width': 0.5,
                            'circle-opacity': 0.65
                        }
                    });
                    console.log('WL: enrichment buildings loaded: ' + geojson.features.length);
                })
                .catch(function (e) {
                    console.warn('WL: enrichment buildings fetch failed:', e);
                });
        }

        // 2. Fetch + render POIs (colored markers + labels + popup)
        function loadPois() {
            var url = '/api/osm/geojson/pois' +
                '?lat=' + encodeURIComponent(lat) +
                '&lon=' + encodeURIComponent(lng) +
                '&radius=5000&limit=500';
            fetch(url, {credentials: 'same-origin'})
                .then(function (r) { return r.json(); })
                .then(function (geojson) {
                    if (!geojson || !geojson.features || !geojson.features.length) {
                        console.log('WL: enrichment POIs empty');
                        return;
                    }
                    if (map.getSource('wl-enriched-pois')) return;
                    map.addSource('wl-enriched-pois', {
                        type: 'geojson',
                        data: geojson
                    });

                    // Circle marker (colored by category via step expression)
                    var catCases = [];
                    Object.keys(COLOR_BY_CATEGORY).forEach(function (cat) {
                        catCases.push(cat);
                        catCases.push(COLOR_BY_CATEGORY[cat]);
                    });
                    map.addLayer({
                        id: 'wl-enriched-pois-circle',
                        type: 'circle',
                        source: 'wl-enriched-pois',
                        minzoom: 12,
                        paint: {
                            'circle-radius': {
                                stops: [[12, 3], [14, 5], [16, 7], [18, 9]]
                            },
                            'circle-color': ['match',
                                ['get', 'landmark_category']
                            ].concat(catCases).concat(['#546e7a']),
                            'circle-stroke-color': '#ffffff',
                            'circle-stroke-width': 1.5,
                            'circle-opacity': 0.95
                        }
                    });

                    // Name label (symbol)
                    map.addLayer({
                        id: 'wl-enriched-pois-label',
                        type: 'symbol',
                        source: 'wl-enriched-pois',
                        minzoom: 14,
                        layout: {
                            'text-field': ['get', 'name'],
                            'text-size': {
                                stops: [[14, 10], [16, 12], [18, 14]]
                            },
                            'text-font': ['Noto Sans Bold'],
                            'text-offset': [0, 1.4],
                            'text-anchor': 'top',
                            'text-allow-overlap': false,
                            'text-ignore-placement': false
                        },
                        paint: {
                            'text-color': '#1a1a1a',
                            'text-halo-color': '#ffffff',
                            'text-halo-width': 2.5
                        }
                    });

                    // Popup on click
                    var popup = new maplibregl.Popup({
                        closeButton: true,
                        closeOnClick: true,
                        offset: 12
                    });
                    map.on('click', 'wl-enriched-pois-circle', function (e) {
                        if (!e.features || !e.features.length) return;
                        var f = e.features[0];
                        var p = f.properties || {};
                        var html = '<div style="min-width:180px;font-family:sans-serif;font-size:13px;line-height:1.5">';
                        html += '<strong style="font-size:14px;color:#7a0c14">' +
                                escapeHtml(p.name || '(tanpa nama)') + '</strong><br/>';
                        if (p.landmark_category) {
                            html += '<span style="color:#666">Kategori: </span>' +
                                    escapeHtml(p.landmark_category) + '<br/>';
                        }
                        if (p.subtype) {
                            html += '<span style="color:#666">Tipe: </span>' +
                                    escapeHtml(p.subtype) + '<br/>';
                        }
                        if (p.phone) {
                            html += '<i class="fa fa-phone" style="color:#1976d2"></i> ' +
                                    escapeHtml(p.phone) + '<br/>';
                        }
                        if (p.rating) {
                            html += '<i class="fa fa-star" style="color:#f5c400"></i> ' +
                                    p.rating + (p.reviews ? ' (' + p.reviews + ' ulasan)' : '') + '<br/>';
                        }
                        if (p.distance_m !== undefined && p.distance_m !== null) {
                            html += '<span style="color:#666">Jarak: </span>' +
                                    p.distance_m + ' m<br/>';
                        }
                        html += '</div>';
                        popup.setLngLat(f.geometry.coordinates)
                            .setHTML(html)
                            .addTo(map);
                    });

                    // Cursor pointer on hover
                    map.on('mouseenter', 'wl-enriched-pois-circle', function () {
                        map.getCanvas().style.cursor = 'pointer';
                    });
                    map.on('mouseleave', 'wl-enriched-pois-circle', function () {
                        map.getCanvas().style.cursor = '';
                    });

                    console.log('WL: enrichment POIs loaded: ' + geojson.features.length);
                })
                .catch(function (e) {
                    console.warn('WL: enrichment POIs fetch failed:', e);
                });
        }

        loadBuildings();
        loadPois();
    }

    function initMap(lat, lng) {
        var container = document.getElementById('wl_delivery_map');
        if (!container) return;
        if (!window.maplibregl) return;

        if (mapInstance) {
            // Already initialized: just fly to new center
            try {
                mapInstance.flyTo({
                    center: [lng, lat],
                    zoom: 16,
                    duration: 800
                });
            } catch (e) {}
            return;
        }

        // Clear loading placeholder
        container.innerHTML = '';

        try {
            mapInstance = new maplibregl.Map({
                container: container,
                style: 'https://tiles.openfreemap.org/styles/liberty',
                center: [lng, lat],
                zoom: 16,
                attributionControl: true,
                // v3.10.16: Lock map orientation on mobile.
                // Disable all rotation/pitch gestures so the
                // map (and HTML markers) never tilt or spin
                // when user does two-finger pinch on touch
                // devices. This keeps both the cabang pin
                // and the user delivery pin perfectly upright.
                dragRotate: false,
                touchPitch: false,
                touchZoomRotate: true  // pinch-zoom OK, but rotation disabled above
            });
            // Extra safety: also disable keyboard rotation
            try { mapInstance.keyboard.disableRotation(); } catch(e) {}

            // Expose for debugging (v3.10.13)
            window._wl_map = mapInstance;

            mapInstance.on('load', function () {
                console.log('WL: map load event fired');
                applyCustomMapStyle(mapInstance);
                addCustomLayers(mapInstance);
                // NEW v3.10.14: load enrichment GeoJSON from
                // wl_osm_enrichment module (/api/osm/geojson/*).
                // Renders real Binangun POIs + buildings on
                // top of the openfreemap base tiles.
                loadEnrichmentLayers(mapInstance, lat, lng);
            });

            // Re-apply on style reload
            mapInstance.on('styledata', function () {
                applyCustomMapStyle(mapInstance);
                addCustomLayers(mapInstance);
                // Note: enrichment layers are NOT re-added
                // here because they have their own GeoJSON
                // sources that survive style changes. Adding
                // them again would throw "source already
                // exists" errors.
            });

            // Custom marker (USER delivery location — blue pin)
            var markerEl = document.createElement('div');
            markerEl.className = 'wl-map-marker';
            markerEl.innerHTML =
                '<div class="wl-map-marker__pin">' +
                '<i class="fa fa-map-marker"></i>' +
                '</div>' +
                '<div class="wl-map-marker__ring"></div>';

            new maplibregl.Marker({
                element: markerEl,
                anchor: 'bottom',
                // v3.10.16: Force marker to always stay upright
                // (viewport-aligned) regardless of any map
                // bearing/pitch. Belt-and-suspenders with the
                // dragRotate:false map option above.
                rotationAlignment: 'viewport',
                pitchAlignment: 'viewport'
            })
                .setLngLat([lng, lat])
                .addTo(mapInstance);

            // ---- v3.10.15: SPECIAL Warung Lakku cabang marker ----
            // Cabang tunggal Warung Lakku: -8.188092, 112.356862 (Binangun, Kab. Blitar)
            // Radius layanan: 15km (sesuai wl_osm_enrichment area config)
            // Marker ini membedakan cabang Warung Lakku dari POI/building biasa:
            //   - Pin maroon tebal dengan icon FA storefront
            //   - Label "WARUNG LAKKU — Binangun" selalu tampil
            //   - Circle 15km boundary (fill maroon 8% + stroke maroon dashed)
            //   - Popup info jam operasional + alamat
            var WL_CABANG = { lat: -8.188092, lng: 112.356862, radiusM: 15000 };

            // (a) 15km service-radius circle (GeoJSON polygon approx via turf-like inline)
            // Kita generate circle polygon manual (64 segments) supaya tidak perlu lib turf.
            function makeCircleGeoJSON(centerLat, centerLng, radiusM, segments) {
                var coords = [];
                var R = 6378137; // earth radius (m)
                for (var i = 0; i <= segments; i++) {
                    var bearing = (i * 360 / segments) * Math.PI / 180;
                    var lat1 = centerLat * Math.PI / 180;
                    var lng1 = centerLng * Math.PI / 180;
                    var dByR = radiusM / R;
                    var lat2 = Math.asin(
                        Math.sin(lat1) * Math.cos(dByR) +
                        Math.cos(lat1) * Math.sin(dByR) * Math.cos(bearing));
                    var lng2 = lng1 + Math.atan2(
                        Math.sin(bearing) * Math.sin(dByR) * Math.cos(lat1),
                        Math.cos(dByR) - Math.sin(lat1) * Math.sin(lat2));
                    coords.push([
                        lng2 * 180 / Math.PI,
                        lat2 * 180 / Math.PI
                    ]);
                }
                return {
                    type: 'Feature',
                    geometry: {
                        type: 'Polygon',
                        coordinates: [coords]
                    },
                    properties: { radiusM: radiusM }
                };
            }

            try {
                var circleSrc = mapInstance.getSource('wl-cabang-radius');
                if (!circleSrc) {
                    mapInstance.addSource('wl-cabang-radius', {
                        type: 'geojson',
                        data: makeCircleGeoJSON(
                            WL_CABANG.lat, WL_CABANG.lng,
                            WL_CABANG.radiusM, 64)
                    });

                    // Fill (maroon 8% opacity, very subtle supaya tidak ganggu POI)
                    mapInstance.addLayer({
                        id: 'wl-cabang-radius-fill',
                        type: 'fill',
                        source: 'wl-cabang-radius',
                        paint: {
                            'fill-color': '#7a0c14',
                            'fill-opacity': 0.06
                        }
                    });

                    // Stroke (maroon dashed, always visible)
                    mapInstance.addLayer({
                        id: 'wl-cabang-radius-stroke',
                        type: 'line',
                        source: 'wl-cabang-radius',
                        paint: {
                            'line-color': '#7a0c14',
                            'line-width': 1.5,
                            'line-dasharray': [4, 3],
                            'line-opacity': 0.7
                        }
                    });
                    console.log('WL: cabang 15km radius circle added');
                }
            } catch (e) {
                console.warn('WL: cabang radius circle failed:', e.message);
            }

            // (b) Cabang marker — storefront icon with maroon pin + label badge
            var cabangEl = document.createElement('div');
            cabangEl.className = 'wl-cabang-marker';
            cabangEl.innerHTML =
                '<div class="wl-cabang-marker__pin">' +
                    '<i class="fa fa-shopping-basket"></i>' +
                '</div>' +
                '<div class="wl-cabang-marker__label">' +
                    '<strong>WARUNG LAKKU</strong>' +
                    '<span>Cabang Binangun</span>' +
                '</div>';

            var cabangMarker = new maplibregl.Marker({
                element: cabangEl,
                anchor: 'bottom',
                // v3.10.16: same as user marker — always upright
                rotationAlignment: 'viewport',
                pitchAlignment: 'viewport'
            })
                .setLngLat([WL_CABANG.lng, WL_CABANG.lat])
                .addTo(mapInstance);

            // (c) Popup on click with full info
            var cabangPopup = new maplibregl.Popup({
                offset: 30,
                closeButton: true,
                closeOnClick: false,
                maxWidth: '280px'
            }).setHTML(
                '<div style="font-family:Inter,sans-serif;padding:4px">' +
                    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">' +
                        '<div style="width:32px;height:32px;border-radius:50%;background:#7a0c14;' +
                             'color:#fff;display:flex;align-items:center;justify-content:center;' +
                             'font-size:14px"><i class="fa fa-shopping-basket"></i></div>' +
                        '<div>' +
                            '<div style="font-weight:700;color:#7a0c14;font-size:14px;line-height:1.1">' +
                                'WARUNG LAKKU</div>' +
                            '<div style="font-size:11px;color:#666;line-height:1.1">' +
                                'Cabang Binangun (Pusat)</div>' +
                        '</div>' +
                    '</div>' +
                    '<div style="font-size:12px;color:#333;line-height:1.5">' +
                        '<i class="fa fa-map-marker me-1" style="color:#7a0c14"></i>' +
                        'Binangun, Kab. Blitar, Jawa Timur<br/>' +
                        '<i class="fa fa-crosshairs me-1" style="color:#7a0c14"></i>' +
                        '-8.188092, 112.356862<br/>' +
                        '<i class="fa fa-circle-o-notch me-1" style="color:#7a0c14"></i>' +
                        'Radius layanan: <strong>15 km</strong><br/>' +
                        '<i class="fa fa-clock-o me-1" style="color:#7a0c14"></i>' +
                        '08.00 — 21.00 WIB setiap hari' +
                    '</div>' +
                    '<div style="margin-top:8px;padding-top:8px;' +
                                 'border-top:1px solid #eee;font-size:11px;color:#888">' +
                        '<i class="fa fa-info-circle me-1"></i>' +
                        'Area abu-abu menunjukkan jangkauan layanan ' +
                        'pengiriman Warung Lakku.' +
                    '</div>' +
                '</div>'
            );

            cabangMarker.setPopup(cabangPopup);

            // (d) Auto-fit supaya circle 15km + user location keduanya terlihat
            //     kalau user location > 5km dari cabang.
            try {
                var userDist = Math.sqrt(
                    Math.pow((lat - WL_CABANG.lat) * 111320, 2) +
                    Math.pow((lng - WL_CABANG.lng) * 111320 *
                        Math.cos(WL_CABANG.lat * Math.PI / 180), 2)
                );
                if (userDist > 5000) {
                    var bounds = new maplibregl.LngLatBounds();
                    bounds.extend([WL_CABANG.lng, WL_CABANG.lat]);
                    bounds.extend([lng, lat]);
                    // Pad sedikit supaya marker tidak mentok edge
                    mapInstance.fitBounds(bounds, {
                        padding: 60,
                        maxZoom: 14
                    });
                    console.log('WL: auto-fit bounds (user ' +
                        Math.round(userDist) + 'm from cabang)');
                }
            } catch (e) {
                console.warn('WL: auto-fit failed:', e.message);
            }

            // Nav controls
            mapInstance.addControl(
                new maplibregl.NavigationControl({visualizePitch: false}),
                'top-right'
            );

            // ---- v3.10.16: Fetch OSRM best route from cabang
            //      to buyer's address and draw it on the map. ----
            // Uses the SAME OSRM server as delivery_osrm_distance
            // module (https://router.project-osrm.org by default,
            // configurable on the carrier record).
            // Pricing logic mirrors the carrier:
            //   - Price per km: Rp 1000
            //   - Min price: Rp 2000
            //   - Round up to next integer km
            fetchOsrmRoute(mapInstance, WL_CABANG, lat, lng);

        } catch (e) {
            console.warn('MapLibre init failed:', e);
            container.innerHTML =
                '<div class="wl-map-modal__error">' +
                '<i class="fa fa-exclamation-triangle me-2"></i>' +
                'Peta tidak dapat dimuat. Silakan klik ' +
                '<strong>Tidak, Atur Ulang</strong> ' +
                'untuk memastikan lokasi Anda.</div>';
        }
    }

    // ---- v3.10.16: OSRM Route fetcher + drawer ----
    // Calls https://router.project-osrm.org/route/v1/driving/
    //   {cabangLng},{cabangLat};{userLng},{userLat}
    //   ?overview=full&geometries=geojson&steps=false
    // Returns route geometry (GeoJSON LineString) + distance
    // (metres) + duration (seconds).
    //
    // Draws the route on the MapLibre map as a maroon line
    // with yellow casing, and populates the route info panel
    // below the map with distance, duration, and estimated
    // shipping price.
    //
    // Pricing config (mirrors delivery_osrm_distance carrier):
    //   - price_per_km: 1000 IDR
    //   - minimum_price: 2000 IDR
    //   - round_up_km: true (1.2km → 2km → 2000 IDR, 2.01km → 3km → 3000 IDR)
    function fetchOsrmRoute(map, cabang, userLat, userLng) {
        var OSRM_SERVER = 'https://router.project-osrm.org';
        var url = OSRM_SERVER + '/route/v1/driving/' +
            cabang.lng.toFixed(6) + ',' + cabang.lat.toFixed(6) + ';' +
            userLng.toFixed(6) + ',' + userLat.toFixed(6) +
            '?overview=full&geometries=geojson&steps=false';

        console.log('WL: fetching OSRM route:', url);

        // Pricing config (sync with delivery_osrm_distance carrier record)
        var PRICE_PER_KM = 1000;
        var MIN_PRICE = 2000;
        var ROUND_UP_KM = true;

        var infoEl = document.getElementById('wl_route_info');
        var statsEl = document.getElementById('wl_route_stats');
        var priceEl = document.getElementById('wl_route_price');

        // Initial loading state
        if (infoEl) {
            infoEl.classList.remove('wl-route-info--error');
            infoEl.classList.add('wl-route-info--loading');
        }
        if (statsEl) statsEl.textContent = 'menghitung rute...';
        if (priceEl) priceEl.innerHTML = '...<small>Estimasi Ongkir</small>';

        fetch(url, { method: 'GET' })
            .then(function (r) {
                if (!r.ok) throw new Error('HTTP ' + r.status);
                return r.json();
            })
            .then(function (data) {
                if (data.code !== 'Ok' || !data.routes || !data.routes.length) {
                    throw new Error('OSRM code: ' + data.code +
                        (data.message ? ' (' + data.message + ')' : ''));
                }
                var route = data.routes[0];
                var distanceM = route.distance || 0;
                var durationS = route.duration || 0;
                var distanceKm = distanceM / 1000.0;
                var durationMin = Math.round(durationS / 60);

                // Pricing: round up to next integer km, multiply, clamp to min
                var billedKm = ROUND_UP_KM
                    ? Math.ceil(distanceKm)
                    : distanceKm;
                var price = billedKm * PRICE_PER_KM;
                if (MIN_PRICE > 0) price = Math.max(price, MIN_PRICE);

                console.log('WL: OSRM route ok — distance=' +
                    distanceKm.toFixed(2) + 'km, duration=' +
                    durationMin + 'min, price=' + price + ' IDR');

                // Draw route geometry on map
                drawRouteOnMap(map, route.geometry, cabang,
                    { lat: userLat, lng: userLng });

                // Update info panel
                if (infoEl) {
                    infoEl.classList.remove('wl-route-info--loading');
                    infoEl.classList.remove('wl-route-info--error');
                }
                if (statsEl) {
                    var distStr = distanceKm < 1
                        ? Math.round(distanceM) + ' m'
                        : distanceKm.toFixed(2) + ' km';
                    var durStr;
                    if (durationMin < 60) {
                        durStr = durationMin + ' menit';
                    } else {
                        var h = Math.floor(durationMin / 60);
                        var m = durationMin % 60;
                        durStr = h + ' jam ' + m + ' menit';
                    }
                    statsEl.innerHTML =
                        '<strong>' + escapeHtml(distStr) + '</strong>' +
                        '<span class="wl-route-info__sep">•</span>' +
                        '<strong>' + escapeHtml(durStr) + '</strong>' +
                        '<span class="wl-route-info__sep">•</span>' +
                        'Billed ' + billedKm + ' km';
                }
                if (priceEl) {
                    var priceStr = 'Rp ' + price.toLocaleString('id-ID');
                    priceEl.innerHTML = escapeHtml(priceStr) +
                        '<small>Estimasi Ongkir</small>';
                }
            })
            .catch(function (err) {
                console.warn('WL: OSRM route failed:', err.message);
                if (infoEl) {
                    infoEl.classList.remove('wl-route-info--loading');
                    infoEl.classList.add('wl-route-info--error');
                }
                if (statsEl) {
                    statsEl.innerHTML = 'Rute tidak dapat dihitung' +
                        '<br/><small style="color:#999;font-size:10px">' +
                        escapeHtml(err.message) + '</small>';
                }
                if (priceEl) {
                    priceEl.innerHTML = '—<small>Estimasi Ongkir</small>';
                }
            });
    }

    // Draw the OSRM route LineString on the map.
    // Renders 2 layers:
    //   - wl-route-casing: thick yellow line under the maroon line
    //     (gives a "road" feel similar to Google Maps directions)
    //   - wl-route-line: maroon 4px line on top
    // Also auto-fits bounds to show the entire route.
    function drawRouteOnMap(map, geometry, cabang, user) {
        if (!map || !geometry) return;
        try {
            // Remove existing route layers/sources if any (for re-renders)
            ['wl-route-line', 'wl-route-casing'].forEach(function (id) {
                if (map.getLayer(id)) map.removeLayer(id);
            });
            if (map.getSource('wl-route')) map.removeSource('wl-route');

            map.addSource('wl-route', {
                type: 'geojson',
                data: {
                    type: 'Feature',
                    geometry: geometry,
                    properties: {}
                }
            });

            // Casing (yellow, thick, drawn first so maroon line sits on top)
            map.addLayer({
                id: 'wl-route-casing',
                type: 'line',
                source: 'wl-route',
                layout: {
                    'line-cap': 'round',
                    'line-join': 'round'
                },
                paint: {
                    'line-color': '#f5c400',
                    'line-width': {
                        stops: [
                            [8, 3],
                            [12, 5],
                            [16, 9],
                            [20, 14]
                        ]
                    },
                    'line-opacity': 0.9
                }
            });

            // Main line (maroon, slightly thinner than casing)
            map.addLayer({
                id: 'wl-route-line',
                type: 'line',
                source: 'wl-route',
                layout: {
                    'line-cap': 'round',
                    'line-join': 'round'
                },
                paint: {
                    'line-color': '#7a0c14',
                    'line-width': {
                        stops: [
                            [8, 1.5],
                            [12, 3],
                            [16, 5],
                            [20, 8]
                        ]
                    },
                    'line-opacity': 1.0
                }
            });

            console.log('WL: OSRM route drawn on map');

            // Auto-fit bounds to show entire route (overrides the
            // earlier 5km auto-fit because the route may extend
            // far beyond cabang↔user straight line)
            try {
                var coords = geometry.coordinates || [];
                if (coords.length > 1) {
                    var bounds = new maplibregl.LngLatBounds();
                    coords.forEach(function (c) { bounds.extend(c); });
                    // Always include cabang + user markers too
                    bounds.extend([cabang.lng, cabang.lat]);
                    bounds.extend([user.lng, user.lat]);
                    map.fitBounds(bounds, {
                        padding: { top: 60, bottom: 80, left: 40, right: 40 },
                        maxZoom: 15
                    });
                    console.log('WL: route auto-fit bounds applied');
                }
            } catch (e) {
                console.warn('WL: route fitBounds failed:', e.message);
            }
        } catch (e) {
            console.warn('WL: drawRouteOnMap failed:', e.message);
        }
    }

    function populateAddress() {
        var modal = getModalEl();
        var addrEl = document.getElementById('wl_delivery_address_text');
        if (!modal || !addrEl) return;
        var addr = modal.dataset.addr || '';
        var name = modal.dataset.name || '';
        var phone = modal.dataset.phone || '';

        var html = '';
        if (name) {
            html += '<strong>' + escapeHtml(name) + '</strong><br/>';
        }
        if (addr) {
            html += '<span style="white-space: pre-line">' +
                    escapeHtml(addr) + '</span>';
        }
        if (phone) {
            html += '<br/><span class="text-muted">' +
                    '<i class="fa fa-phone me-1"></i>' +
                    escapeHtml(phone) + '</span>';
        }
        addrEl.innerHTML = html;
    }

    function escapeHtml(s) {
        if (s === null || s === undefined) return '';
        // CRITICAL: do NOT use HTML entities like
        // amp-hash-39 or amp-amp in this function.
        // The XML parser unescapes them once, then
        // QWeb does NOT re-escape them on output, so
        // the JS string ends up with literal chars
        // that break the syntax (e.g. the entity for
        // apostrophe becomes a bare single quote,
        // turning the replacement string into a
        // syntax error "missing ) after argument
        // list").
        //
        // Use JS Unicode escapes instead:
        //   backslash-u-0026 = ampersand char
        //   backslash-u-0027 = apostrophe char
        // These are invisible to the XML parser and
        // evaluate at JS runtime to the right char.
        // So the JS string "backslash-u-0026 hash 39"
        // evaluates to the 5-char HTML entity string
        // which is what we want as the escapeHtml
        // output for an apostrophe.
        return String(s)
            .replace(/\u0026/g, '\u0026amp;')
            .replace(/\u003c/g, '\u0026lt;')
            .replace(/\u003e/g, '\u0026gt;')
            .replace(/\u0022/g, '\u0026quot;')
            .replace(/\u0027/g, '\u0026#39;');
    }

    function openDeliveryModal() {
        var modalEl = getModalEl();
        if (!modalEl) return;
        var coords = getPartnerCoords();
        if (!coords.hasCoords) return;

        // IMPORTANT: do NOT set modalState to "showing"
        // yet. If Bootstrap Modal class isn't loaded
        // yet (the IIFE may run before Odoo's asset
        // bundle finishes loading Bootstrap), we need
        // to leave modalState at "not_shown" so the
        // next init() retry can attempt to open the
        // modal again. Otherwise modalState gets
        // stuck at "dismissed" and the modal never
        // opens even after Bootstrap is ready.
        var modal = getModalInstance(modalEl);
        if (!modal) {
            console.warn('WL: Bootstrap Modal not yet loaded, will retry on next init()');
            return;
        }

        modalState = "showing";
        populateAddress();

        var onShown = function () {
            // Lazy-load MapLibre, then init the map.
            loadMapLibre(function () {
                initMap(coords.lat, coords.lng);
            });
            modalEl.removeEventListener('shown.bs.modal', onShown);
        };
        modalEl.addEventListener('shown.bs.modal', onShown);

        var onHidden = function () {
            if (modalState === 'showing') {
                modalState = 'dismissed';
            }
            modalEl.removeEventListener('hidden.bs.modal', onHidden);
        };
        modalEl.addEventListener('hidden.bs.modal', onHidden);

        try {
            modal.show();
        } catch (e) {
            console.warn('WL: modal.show() failed:', e);
            modalState = 'dismissed';
        }
    }

    function setupModalButtons() {
        var modalEl = getModalEl();
        if (!modalEl) return;
        var yesBtn = document.getElementById('wl_delivery_confirm_yes');
        if (yesBtn && !yesBtn._wlBound) {
            yesBtn._wlBound = true;
            yesBtn.addEventListener('click', function () {
                modalState = 'confirmed';
                var modal = getModalInstance(modalEl);
                if (modal) {
                    try { modal.hide(); } catch (e) {}
                }
            });
        }
        // "no" button is just an <a href="/shop/address">,
        // no JS handler needed.
    }

    // ---- main banner updater (called on every change/click
    //      and on MutationObserver ticks) ----
    function updateBanners() {
        var radio = getSelectedRadio();
        var banner = document.getElementById('pickup_info_banner');
        var warning = document.getElementById('wl_gps_warning');
        if (!banner || !warning) return;

        if (isPickupSelected(radio)) {
            // Pickup mode: show pickup banner, hide GPS warning.
            banner.classList.remove('d-none');
            warning.classList.add('d-none');
            return;
        }

        // Not pickup: hide pickup banner unconditionally.
        banner.classList.add('d-none');

        if (isDistanceCarrier(radio)) {
            var coords = getPartnerCoords();
            if (coords.hasCoords) {
                // Has GPS: hide warning, maybe open modal.
                warning.classList.add('d-none');
                if (modalState === 'not_shown') {
                    openDeliveryModal();
                }
            } else {
                // No GPS: show warning if price badge indicates error.
                var badge = getSelectedPriceBadge(radio);
                if (priceBadgeHasError(badge)) {
                    warning.classList.remove('d-none');
                } else {
                    warning.classList.add('d-none');
                }
            }
        } else {
            // Some other carrier (e.g. flat rate): no warning.
            warning.classList.add('d-none');
        }
    }

    // ---- event delegation (survives AJAX re-renders) ----
    function onAnyChange(evt) {
        var target = evt.target;
        if (!target) return;
        if (target.name === 'delivery_type' ||
            target.id === 'delivery_type' ||
            (target.closest && target.closest('#delivery_method'))) {
            // Defer so Odoo's own handlers finish first.
            setTimeout(updateBanners, 50);
            setTimeout(updateBanners, 300);
        }
    }
    document.addEventListener('change', onAnyChange, true);
    document.addEventListener('click', onAnyChange, true);

    function setupObserver() {
        var dm = document.getElementById('delivery_method');
        if (!dm) return false;
        var obs = new MutationObserver(function () {
            setTimeout(updateBanners, 50);
            setTimeout(updateBanners, 400);
        });
        obs.observe(dm, {
            childList: true,
            subtree: true,
            attributes: true,
            attributeFilter: ['checked', 'class', 'data-is-pickup']
        });
        return true;
    }

    function init() {
        setupModalButtons();
        updateBanners();
        if (!setupObserver()) {
            setTimeout(init, 200);
            setTimeout(init, 800);
            setTimeout(init, 1500);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
    setTimeout(init, 1000);
    setTimeout(init, 2500);
    setTimeout(init, 4000);
    //
})();
//
